### Configure Recharts Line Chart Animation in React

Source: https://context7.com/recharts/recharts/llms.txt

This React component demonstrates how to control animation properties for a Line chart using Recharts. It includes setting `animationDuration`, `animationEasing`, `animationBegin`, and handling `onAnimationStart`/`onAnimationEnd` callbacks. A button is provided to replay the animation by changing the chart's key.

```jsx
import React, { useState } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const data = [
  { name: 'Page A', uv: 4000 },
  { name: 'Page B', uv: 3000 },
  { name: 'Page C', uv: 2000 },
  { name: 'Page D', uv: 2780 },
  { name: 'Page E', uv: 1890 },
];

function AnimationExample() {
  const [animationKey, setAnimationKey] = useState(0);

  return (
    <div>
      <button onClick={() => setAnimationKey(prev => prev + 1)}>
        Replay Animation
      </button>

      <ResponsiveContainer width="100%" height={400}>
        <LineChart data={data} key={animationKey}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis />
          <Tooltip />
          <Line
            type="monotone"
            dataKey="uv"
            stroke="#8884d8"
            isAnimationActive={true}
            animationDuration={2000}
            animationEasing="ease-in-out"
            animationBegin={0}
            onAnimationStart={() => console.log('Animation started')}
            onAnimationEnd={() => console.log('Animation ended')}
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

export default AnimationExample;
```

